import { NextRequest, NextResponse } from "next/server"

export async function POST(request: NextRequest) {
  try {
    // Prendiamo i dati che arrivano dal form
    const body = await request.json()
    const { businessName, city } = body

    // Verifichiamo che i dati ci siano
    if (!businessName || !city) {
      return NextResponse.json(
        { error: "Nome attività e città sono obbligatori" },
        { status: 400 }
      )
    }

    // Per ora restituiamo dati finti — li sostituiremo con quelli veri
    return NextResponse.json({
      businessName,
      city,
      omniScore: 72,
      reputation: {
        score: 80,
        rating: 4.3,
        totalReviews: 127,
      },
      visibility: {
        score: 65,
        foundOnGoogle: true,
        hasWebsite: true,
      },
      social: {
        score: 60,
        hasInstagram: true,
        hasFacebook: false,
      },
      actionPlan: [
        {
          priority: 1,
          action: "Rispondi alle recensioni negative su Google",
          impact: "Alto",
        },
        {
          priority: 2,
          action: "Crea una pagina Facebook per l'attività",
          impact: "Medio",
        },
        {
          priority: 3,
          action: "Aggiorna gli orari su Google Business Profile",
          impact: "Alto",
        },
      ],
    })
  } catch (error) {
    return NextResponse.json(
      { error: "Errore interno del server" },
      { status: 500 }
    )
  }
}